import aside from '@/components/shared/aside/aside';
import nav from '@/components/shared/nav/nav';
import { ComponentModule, render } from '@/main';
import { Empresa } from '@/models/empresa';
import { TOAST_TRIGGER } from '@/models/events';
import { Poblacion } from '@/models/poblacion';
import {
    EmptyShipmentDetails,
    Presale,
    PresaleActivity,
    PresaleClientType,
    PresaleCompanyType,
    PresaleCountry,
    PresaleIva,
    PresalePaymentDay,
    PresalePaymentMode,
    PresaleShippingDetails,
    PresaleZone,
} from '@/models/presunto';
import { Provincia } from '@/models/provincia';
import { ToastError, ToastSuccess } from '@/models/toast';
import { User } from '@/models/user';
import { Vendedor } from '@/models/vendedor';
import { url, getCompanyGlobalData } from '@/services/api.service';
import { getAuthenticatedUser } from '@/services/auth.service';
import { Modal } from 'flowbite';

export default {
    name: () => 'presaleEdit',
    template: () => import('./presale-edit.html?raw'),
    data: () => ({
        // Generic properties
        user: null as User | null,
        empresa: null as Empresa | null,

        // x-html components
        nav: null as string | null,
        aside: null as string | null,

        // loading states
        loading: true,

        // form states
        submitting: false,
        provinciaSelected: false,

        // presale generic
        presale: null as Presale | null,

        // edited presale
        editedPresale: null as Presale | null,

        // general data
        provincias: [] as Provincia[],
        poblaciones: [] as Poblacion[],

        // presale data
        ivas: [] as PresaleIva[],
        modosPago: [] as PresalePaymentMode[],
        diasPago: [] as PresalePaymentDay[],
        paises: [] as PresaleCountry[],
        tiposCliente: [] as PresaleClientType[],
        tiposEmpresa: [] as PresaleCompanyType[],
        vendedores: [] as Vendedor[],
        cobradores: [] as Vendedor[],
        zonas: [] as PresaleZone[],
        actividades: [] as PresaleActivity[],
        direccionesEnvio: [] as PresaleShippingDetails[],

        // modals
        modalShipmentEdit: null as Modal | null,
        modalShipmentDelete: null as Modal | null,
        modalShipmentAdd: null as Modal | null,
        modalValidatePresale: null as Modal | null,

        // table loading
        loadingPresaleShipmentDetails: false,

        // table selection
        currentShipmentDetails: EmptyShipmentDetails,

        // Tabs
        tabs: [
            { id: 0, text: 'Datos de cliente', formRef: 'formDatosCliente' }, // TODO: use translation service
            { id: 1, text: 'Datos de facturación', formRef: 'formDatosFacturacion' }, // TODO: use translation service
            { id: 2, text: 'Clasificación de cliente', formRef: 'formClasificacionCliente' }, // TODO: use translation service
            { id: 3, text: 'Direcciones de envío', formRef: 'tableShipmentDetails' }, // TODO: use translation service
        ],
        currentTabId: 0,

        async init() {
            console.log('presale-edit@init');

            try {
                this.user = await getAuthenticatedUser();
                this.empresa = await getCompanyGlobalData(this.user.empOmi);
            } catch (error) {
                location.href = '/login';
            }

            this.nav = await render(nav);
            this.aside = await render(aside);

            await Promise.all([
                this.loadPresale(),
                this.loadIvas(),
                this.loadPaymentModes(),
                this.loadPaymentDays(),
                this.loadCountries(),
                this.loadClientTypes(),
                this.loadZones(),
                this.loadCompanyTypes(),
                this.loadActivities(),
                this.loadSellers(),
            ]);

            this.initModalAddShipmentDetail();
            this.initModalDeleteShipmentDetail();
            this.initModalValidatePresale();

            this.$watch('currentTabId', async () => {
                if (this.currentTabId === 3) {
                    await this.loadShippingDetails();
                }
            });

            this.$nextTick(() => {
                console.log('101-presale-edit@nextTick');

                console.log(this.presale, 'presale');
            });

            this.loading = false;
        },

        initModalAddShipmentDetail() {
            this.modalShipmentAdd = new Modal(
                this.$refs.modalShipmentAdd,
                {
                    placement: 'center',
                    backdrop: 'static', // Prevent closing the modal when clicking outside
                    backdropClasses: 'bg-gray-900/50 dark:bg-gray-900/80 fixed inset-0 z-40',
                    closable: true,
                    onHide: () => {
                        console.log('modal is hidden');
                    },
                    onShow: () => {
                        console.log('modal is shown');
                    },
                    onToggle: () => {
                        console.log('modal has been toggled');
                    },
                },
                {
                    id: 'modal-shipment-add',
                    override: true,
                },
            );
        },

        initModalEditShipmentDetail() {
            this.modalShipmentEdit = new Modal(
                this.$refs.modalShipmentEdit,
                {
                    placement: 'center',
                    backdrop: 'static', // Prevent closing the modal when clicking outside
                    backdropClasses: 'bg-gray-900/50 dark:bg-gray-900/80 fixed inset-0 z-40',
                    closable: true,
                    onHide: () => {
                        console.log('modal is hidden');
                    },
                    onShow: () => {
                        console.log('modal is shown');
                    },
                    onToggle: () => {
                        console.log('modal has been toggled');
                    },
                },
                {
                    id: 'modalShipmentEdit',
                    override: true,
                },
            );
        },

        initModalDeleteShipmentDetail() {
            this.modalShipmentDelete = new Modal(
                this.$refs.modalShipmentDelete,
                {
                    placement: 'center',
                    backdrop: 'dynamic',
                    backdropClasses: 'bg-gray-900/50 dark:bg-gray-900/80 fixed inset-0 z-40',
                    closable: true,
                    onHide: () => {
                        console.log('modal is hidden');
                    },
                    onShow: () => {
                        console.log('modal is shown');
                    },
                    onToggle: () => {
                        console.log('modal has been toggled');
                    },
                },
                {
                    id: `modal-shipment-delete-${this.currentShipmentDetails.nroenv}`,
                    override: true,
                },
            );
        },

        initModalValidatePresale() {
            this.modalValidatePresale = new Modal(
                this.$refs.modalValidatePresale,
                {
                    placement: 'center',
                    backdrop: 'dynamic',
                    backdropClasses: 'bg-gray-900/50 dark:bg-gray-900/80 fixed inset-0 z-40',
                    closable: true,
                    onHide: () => {
                        console.log('modal is hidden');
                    },
                    onShow: () => {
                        console.log('modal is shown');
                    },
                    onToggle: () => {
                        console.log('modal has been toggled');
                    },
                },
                {
                    id: 'modal-validate-presale',
                    override: true,
                },
            );
        },

        openAddShipmentDetailModal() {
            this.provinciaSelected = false;
            this.$refs.formModalAddShipment.reset();
            this.modalShipmentAdd?.show();
        },

        openValidateModal() {
            this.modalValidatePresale?.show();
        },

        async openEditShipmentDetailModal(shipmentDetail: PresaleShippingDetails) {
            this.currentShipmentDetails = { ...shipmentDetail };
            await this.loadPoblaciones(this.currentShipmentDetails.pro);
            this.modalShipmentEdit?.show();
        },

        openDeleteShipmentDetailModal(shipmentDetail: PresaleShippingDetails) {
            this.currentShipmentDetails = shipmentDetail;
            this.modalShipmentDelete?.show();
        },

        submitFormByEvent(e: SubmitEvent) {
            console.log('submitFormByEvent', e.submitter?.innerText);
            e.preventDefault();
            const formElement = e.target as HTMLFormElement;

            this.submitForm(formElement);
        },

        submitForm(formElement: HTMLFormElement) {
            const form = new FormData(formElement);
            const presaleData = Object.fromEntries(form.entries());

            this.editedPresale = {
                ...this.editedPresale,
                ...presaleData,
            };

            console.log(this.editedPresale);
        },

        submitFormByRef(targetFormRefName: string, targetTab: number) {
            if (targetFormRefName !== 'tableShipmentDetails') {
                const form = this.$refs[targetFormRefName] as HTMLFormElement;
                if (!form.checkValidity()) {
                    form.reportValidity();
                    return;
                }
                this.submitForm(form);
            }
            this.currentTabId = targetTab;
        },

        async savePresale() {
            try {
                this.submitting = true;
                const r = await fetch(url(`isiWeb/web/v1/empresas/01/presuntos/${this.$router.params['pre']}`), {
                    credentials: 'include',
                    method: 'PUT',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        ...this.editedPresale,
                        perfac: +this.editedPresale.perfac,
                        rietotcon: +this.editedPresale.rietotcon,
                        ivc: this.editedPresale.ivc === 'true',
                        abf: this.editedPresale.abf === 'on',
                        enviarfacturaelectronica: this.editedPresale.enviarfacturaelectronica === 'on',
                        enviarfacturaemail: this.editedPresale.enviarfacturaemail === 'on',
                        cobrador: +this.editedPresale.cobrador,
                    }),
                });

                if (!r.ok) {
                    const response = await r.json();
                    throw new Error(response.message);
                }

                const response = await r.json();
                this.$router.navigate('/presunto/modify');
                this.$dispatch(TOAST_TRIGGER, { msg: response.message, level: ToastSuccess });
            } catch (error: any) {
                console.error(error);
                this.submitting = false;
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
            }
        },

        async addShipmentDetails(e: SubmitEvent) {
            const data = new FormData(e.target as HTMLFormElement);
            const newShipment = Object.fromEntries(data.entries());

            const shipmentDetails = {
                cif: this.presale?.cif,
                dup: this.presale?.dup,
                ...newShipment,
            } as PresaleShippingDetails;

            this.submitting = true;
            try {
                const r = await fetch(
                    url(`isiWeb/web/v1/empresas/01/presuntos/${this.$router.params['pre']}/direcciones-envio`),
                    {
                        credentials: 'include',
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                        body: JSON.stringify(shipmentDetails),
                    },
                );

                if (!r.ok) {
                    const response = await r.json();
                    throw new Error(response.message);
                }

                await this.loadShippingDetails();
                this.modalShipmentAdd?.hide();
                this.$dispatch(TOAST_TRIGGER, { msg: 'Dirección de envío añadida', level: ToastSuccess });
            } catch (error: any) {
                console.error(error);
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
            }
            this.submitting = false;
        },

        async editShipmentDetails(e: SubmitEvent) {
            const data = new FormData(e.target as HTMLFormElement);
            const editedShipment = Object.fromEntries(data.entries());

            try {
                this.submitting = true;
                const r = await fetch(
                    url(
                        `isiWeb/web/v1/empresas/01/presuntos/${this.$router.params['pre']}/direcciones-envio/${this.currentShipmentDetails.nroenv}`,
                    ),
                    {
                        credentials: 'include',
                        method: 'PUT',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                        body: JSON.stringify({
                            ...this.currentShipmentDetails,
                            ...editedShipment,
                        } as PresaleShippingDetails),
                    },
                );

                if (!r.ok) {
                    const response = await r.json();
                    throw new Error(response.message);
                }

                await this.loadShippingDetails();
                this.currentShipmentDetails = EmptyShipmentDetails;
                this.modalShipmentEdit?.hide();
                this.submitting = false;
                this.$dispatch(TOAST_TRIGGER, { msg: 'Dirección de envío actualizada', level: ToastSuccess });
            } catch (error: any) {
                console.error(error);
                this.submitting = false;
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
            }
        },

        async validatePresale() {
            this.submitting = true;
            const validationDate = `${new Date().getFullYear()}-${new Date().getMonth() + 1}-${new Date().getDate()}`;
            try {
                const r = await fetch(url(`isiWeb/web/v1/empresas/01/presuntos/${this.$router.params['pre']}`), {
                    credentials: 'include',
                    method: 'PUT',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    body: JSON.stringify({
                        ...this.presale,
                        conf: true,
                        fecconf: validationDate,
                        usuconf: this.user?.usuario,
                    } as Presale),
                });

                if (!r.ok) {
                    const response = await r.json();
                    throw new Error(response.message);
                }

                const response = await r.json();

                this.modalValidatePresale?.hide();
                this.submitting = false;
                this.$router.navigate('/presunto/modify');
                this.$dispatch(TOAST_TRIGGER, { msg: response.message, level: ToastSuccess });
            } catch (error: any) {
                console.error(error);
                this.submitting = false;
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
            }
        },

        async deleteShipmentDetail(shipmentDetail: PresaleShippingDetails) {
            this.submitting = true;
            try {
                const r = await fetch(
                    url(
                        `isiWeb/web/v1/empresas/01/presuntos/${this.$router.params['pre']}/direcciones-envio/${shipmentDetail.nroenv}`,
                    ),
                    {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                        method: 'DELETE',
                    },
                );

                if (!r.ok) {
                    const response = await r.json();
                    throw new Error(response.message);
                }

                await this.loadShippingDetails();
                this.currentShipmentDetails = EmptyShipmentDetails;

                this.modalShipmentDelete?.hide();
                this.$dispatch(TOAST_TRIGGER, { msg: 'Dirección de envío eliminada', level: ToastSuccess });
            } catch (error: any) {
                console.log('error', error);
                this.$dispatch(TOAST_TRIGGER, { msg: error, level: ToastError });
            }
            this.submitting = false;
        },

        async loadPresale() {
            try {
                const r = await fetch(url(`isiWeb/web/v1/empresas/01/presuntos/${this.$router.params['pre']}`), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading presale');
                }

                this.presale = response.data as Presale;
                this.editedPresale = { ...this.presale };
                await this.loadProvincias();
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadProvincias() {
            try {
                const r = await fetch(url('isiWeb/web/v1/provincias'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading provincias');
                }

                this.provincias = response.data as Provincia[];

                if (this.presale?.pro) {
                    const provincia = this.provincias.find((p: Provincia) => p.pro === this.presale?.pro);

                    if (provincia) {
                        await this.loadPoblaciones(provincia.pro);
                    }
                }
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadPoblaciones(provinciaPro: string) {
            this.provinciaSelected = true;
            try {
                const r = await fetch(url(`isiWeb/web/v1/provincias/${provinciaPro}/poblaciones`), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading poblaciones');
                }

                this.poblaciones = response.data as Poblacion[];
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadIvas() {
            try {
                const r = await fetch(url('isiWeb/web/v1/ivas'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading ivas');
                }

                this.ivas = response.data as PresaleIva[];
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadPaymentModes() {
            try {
                const r = await fetch(url('isiWeb/web/v1/empresas/01/modos-pago'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading payment modes');
                }

                this.modosPago = response.data as PresalePaymentMode[];
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadPaymentDays() {
            try {
                const r = await fetch(url('isiWeb/web/v1/empresas/01/dias-pago'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading payment days');
                }

                this.diasPago = response.data as PresalePaymentDay[];
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadCountries() {
            try {
                const r = await fetch(url('isiWeb/web/v1/paises'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading countries');
                }

                this.paises = response.data as PresaleCountry[];
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadClientTypes() {
            try {
                const r = await fetch(url('isiWeb/web/v1/empresas/01/tipos-cliente'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading client types');
                }

                this.tiposCliente = response.data as PresaleClientType[];
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadZones() {
            try {
                const r = await fetch(url('isiWeb/web/v1/empresas/01/zonas'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading zones');
                }

                this.zonas = response.data as PresaleZone[];
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadCompanyTypes() {
            try {
                const r = await fetch(url('isiWeb/web/v1/tipos-empresa'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading company types');
                }

                this.tiposEmpresa = response.data as PresaleCompanyType[];
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadActivities() {
            try {
                const r = await fetch(url('isiWeb/web/v1/actividades'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading activities');
                }

                this.actividades = response.data as PresaleActivity[];
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadSellers() {
            try {
                const r = await fetch(url('isiWeb/web/v1/empresas/01/vendedores'), {
                    credentials: 'include',
                    headers: {
                        'Content-Type': 'application/json',
                    },
                    method: 'GET',
                });

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading sellers');
                }

                this.vendedores = response.data as Vendedor[];
                this.cobradores = { ...this.vendedores };
            } catch (error: any) {
                console.error(error);
            }
        },

        async loadShippingDetails() {
            this.loadingPresaleShipmentDetails = true;
            try {
                const r = await fetch(
                    url(`isiWeb/web/v1/empresas/01/presuntos/${this.$router.params['pre']}/direcciones-envio`),
                    {
                        credentials: 'include',
                        headers: {
                            'Content-Type': 'application/json',
                        },
                        method: 'GET',
                    },
                );

                const response = await r.json();

                if (!r.ok) {
                    throw new Error('Error loading shipping details');
                }

                this.direccionesEnvio = response.data as PresaleShippingDetails[];
            } catch (error: any) {
                console.error(error);
            }
            this.loadingPresaleShipmentDetails = false;
        },
    }),
} as ComponentModule;
